        id: 9,
        title: { uk: "Логічні оператори and, or, not", ru: "Логические операторы and, or, not" },
        canvasMode: false,
        theory: { uk: "<div class=\"theory-block\"><h3>🧠 and, or, not</h3><pre class=\"code-example\">age = 15\nhas_ticket = True\n\n# and — обидві умови True\nif age >= 12 and has_ticket:\n    print(\"Вхід дозволено\")\n\n# or — хоча б одна True\nif age < 6 or age >= 65:\n    print(\"Безкоштовно\")\n\n# not — інвертує\nif not has_ticket:\n    print(\"Потрібен квиток\")</pre></div><div class=\"theory-block hint\"><h3>📊 Таблиця істинності</h3><pre class=\"code-example\">print(True and True)   # True\nprint(True and False)  # False\nprint(False or True)   # True\nprint(False or False)  # False\nprint(not True)        # False\n\n# Ланцюги порівнянь\nx = 5\nprint(1 < x < 10)   # True\nprint(x > 0 and x % 2 != 0)  # True (>0 і непарне)</pre></div>", ru: "<div class=\"theory-block\"><h3>🧠 and, or, not</h3><pre class=\"code-example\">age = 15\nhas_ticket = True\n\n# and — оба условия True\nif age >= 12 and has_ticket:\n    print(\"Вход разрешён\")\n\n# or — хотя бы одно True\nif age < 6 or age >= 65:\n    print(\"Бесплатно\")\n\n# not — инвертирует\nif not has_ticket:\n    print(\"Нужен билет\")</pre></div><div class=\"theory-block hint\"><h3>📊 Таблица истинности</h3><pre class=\"code-example\">print(True and True)   # True\nprint(True and False)  # False\nprint(False or True)   # True\nprint(False or False)  # False\nprint(not True)        # False\n\n# Цепи сравнений\nx = 5\nprint(1 < x < 10)   # True\nprint(x > 0 and x % 2 != 0)  # True (>0 и нечётное)</pre></div>" },
