        starterCode: "# Урок 9 — Логічні оператори\n\nage = 16\nhas_ticket = True\nis_vip = False\n\n# and — обидві умови мають бути True\nif age >= 16 and has_ticket:\n    print(\"Вхід дозволено\")\n\n# or — достатньо однієї умови\nif has_ticket or is_vip:\n    print(\"Доступ є\")\n\n# not — інверсія\nif not is_vip:\n    print(\"VIP-зони немає\")\n\n# Складна умова\nif age >= 18 and (has_ticket or is_vip):\n    print(\"Повний доступ\")\nelse:\n    print(\"Обмежений доступ\")"
