        starterCode: "# Урок 47 — Менеджер задач\n# Запускай у VS Code!\nimport json, heapq\nfrom datetime import datetime\n\nclass TaskManager:\n    def __init__(self):\n        self._tasks = {}    # id → task\n        self._heap = []     # (priority, id) для швидкого пошуку\n        self._next_id = 1\n\n    def add(self, title, priority=3, tags=None):\n        tid = self._next_id\n        self._next_id += 1\n        task = {\n            \"id\": tid, \"title\": title,\n            \"priority\": priority, \"status\": \"pending\",\n            \"tags\": tags or [],\n            \"created\": datetime.now().strftime(\"%Y-%m-%d %H:%M\")\n        }\n        self._tasks[tid] = task\n        heapq.heappush(self._heap, (priority, tid))\n        print(f\"✅ #{tid} [{priority}⭐] {title}\")\n        return tid\n\n    def complete(self, tid):\n        if tid in self._tasks:\n            self._tasks[tid][\"status\"] = \"done\"\n            print(f\"✓ #{tid} виконано\")\n\n    def delete(self, tid):\n        if tid in self._tasks:\n            del self._tasks[tid]\n            print(f\"🗑 #{tid} видалено\")\n\n    def show(self, only_pending=False):\n        tasks = sorted(self._tasks.values(), key=lambda t: t[\"priority\"])\n        for t in tasks:\n            if only_pending and t[\"status\"] == \"done\": continue\n            icon = \"✓\" if t[\"status\"] == \"done\" else \"○\"\n            tags = f\" [{', '.join(t['tags'])}]\" if t[\"tags\"] else \"\"\n            print(f\"  [{icon}] #{t['id']} P{t['priority']} {t['title']}{tags}\")\n\n    def next_task(self):\n        while self._heap:\n            priority, tid = self._heap[0]\n            if tid in self._tasks and self._tasks[tid][\"status\"] == \"pending\":\n                return self._tasks[tid]\n            heapq.heappop(self._heap)\n        return None\n\ntm = TaskManager()\ntm.add(\"Вивчити рекурсію\", 1, [\"python\", \"алгоритми\"])\ntm.add(\"Зробити проект\", 2, [\"python\"])\ntm.add(\"Прочитати книгу\", 3, [\"читання\"])\ntm.add(\"Прибрати кімнату\", 4)\ntm.add(\"Переглянути серіал\", 5, [\"відпочинок\"])\n\nprint(\"\\n=== Всі задачі ===\")\ntm.show()\n\ntm.complete(1)\nprint(\"\\n=== Тільки незавершені ===\")\ntm.show(only_pending=True)\n\nnt = tm.next_task()\nprint(f\"\\n📌 Наступна задача: {nt['title']}\")"
