      starterCode: `# Урок 49 — Layout: Entry, Frame, grid
# Запускай у VS Code: python урок_049.py
import tkinter as tk

root = tk.Tk()
root.title("Конвертер одиниць")
root.geometry("380x280")
root.config(bg="#1a1f2e")

def lbl(text, row, col):
    tk.Label(root, text=text, bg="#1a1f2e", fg="#9ca3af",
             font=("Arial", 11)).grid(row=row, column=col,
             sticky="w", padx=12, pady=6)

def entry(row, col, width=18):
    e = tk.Entry(root, width=width, font=("Arial", 12),
                 bg="#161a24", fg="white",
                 insertbackground="white", relief="flat",
                 highlightthickness=1, highlightbackground="#4a9eff")
    e.grid(row=row, column=col, padx=12, pady=6)
    return e

lbl("Кілометри:", 0, 0)
km_entry = entry(0, 1)
lbl("Милі:", 1, 0)
miles_entry = entry(1, 1)
lbl("Кг:", 2, 0)
kg_entry = entry(2, 1)
lbl("Фунти:", 3, 0)
lbs_entry = entry(3, 1)

def convert():
    try:
        km = float(km_entry.get())
        miles_entry.delete(0, "end")
        miles_entry.insert(0, f"{km * 0.621371:.4f}")
    except ValueError: pass
    try:
        kg = float(kg_entry.get())
        lbs_entry.delete(0, "end")
        lbs_entry.insert(0, f"{kg * 2.20462:.4f}")
    except ValueError: pass

tk.Button(root, text="Конвертувати", command=convert,
          font=("Arial", 12, "bold"), bg="#4a9eff", fg="white",
          relief="flat", padx=20, pady=8)\
  .grid(row=4, column=0, columnspan=2, pady=16)

root.mainloop()`
