        starterCode: `# Урок 75 — REST API
from flask import Flask, jsonify, request, abort

app = Flask(__name__)

PRODUCTS = [
    {"id":1,"name":"Клавіатура","category":"peripherals","price":450,"in_stock":True},
    {"id":2,"name":"Мишка","category":"peripherals","price":280,"in_stock":True},
    {"id":3,"name":"Монітор","category":"display","price":4200,"in_stock":False},
    {"id":4,"name":"SSD 500GB","category":"storage","price":1650,"in_stock":True},
]
_next_id = 5

def find(pid):
    return next((p for p in PRODUCTS if p['id']==pid), None)

@app.route('/api/products', methods=['GET','POST'])
def products():
    global _next_id
    if request.method == 'GET':
        result = PRODUCTS[:]
        q = request.args.get('q')
        if q: result = [p for p in result if q.lower() in p['name'].lower()]
        cat = request.args.get('category')
        if cat: result = [p for p in result if p['category']==cat]
        return jsonify({"products": result, "total": len(result)})
    data = request.get_json() or {}
    if 'name' not in data:
        return jsonify({"error":"name required"}), 400
    item = {"id": _next_id, "name": data['name'],
            "category": data.get('category',''), "price": data.get('price',0),
            "in_stock": data.get('in_stock', True)}
    _next_id += 1
    PRODUCTS.append(item)
    return jsonify(item), 201

@app.route('/api/products/<int:pid>', methods=['GET','PUT','DELETE'])
def product(pid):
    item = find(pid)
    if not item: abort(404)
    if request.method == 'GET':
        return jsonify(item)
    if request.method == 'DELETE':
        PRODUCTS.remove(item); return '', 204
    item.update(request.get_json() or {})
    return jsonify(item)

@app.route('/api/stats')
def stats():
    return jsonify({
        "total": len(PRODUCTS),
        "in_stock": sum(1 for p in PRODUCTS if p['in_stock']),
        "avg_price": round(sum(p['price'] for p in PRODUCTS)/len(PRODUCTS), 2)
    })

if __name__ == '__main__':
    print("REST API на http://localhost:5002/api/products")
    app.run(debug=True, port=5002)`
