        starterCode: `# Урок 83 — Repository Pattern
import sqlite3
from dataclasses import dataclass, field
from typing import Optional

DB_FILE = "books.db"

@dataclass
class Book:
    title:  str
    author: str
    price:  float
    genre:  str = "Невідомо"
    id:     Optional[int] = field(default=None, repr=False)

class BookRepo:
    def __init__(self, db_path: str = DB_FILE):
        self._conn = sqlite3.connect(db_path)
        self._conn.row_factory = sqlite3.Row
        self._init_table()

    def _init_table(self):
        self._conn.execute("""
            CREATE TABLE IF NOT EXISTS books (
                id     INTEGER PRIMARY KEY AUTOINCREMENT,
                title  TEXT NOT NULL,
                author TEXT NOT NULL,
                price  REAL NOT NULL DEFAULT 0,
                genre  TEXT DEFAULT 'Невідомо'
            )""")
        self._conn.commit()

    def add(self, book: Book) -> Book:
        cur = self._conn.execute(
            "INSERT INTO books (title,author,price,genre) VALUES (?,?,?,?)",
            (book.title, book.author, book.price, book.genre))
        self._conn.commit()
        book.id = cur.lastrowid
        return book

    def bulk_add(self, books):
        with self._conn:
            self._conn.executemany(
                "INSERT INTO books (title,author,price,genre) VALUES (?,?,?,?)",
                [(b.title, b.author, b.price, b.genre) for b in books])
        print(f"  ✅ Додано {len(books)} книг")

    def get_all(self):
        return [self._r(r) for r in
                self._conn.execute("SELECT * FROM books ORDER BY title").fetchall()]

    def find_by_author(self, author: str):
        return [self._r(r) for r in self._conn.execute(
            "SELECT * FROM books WHERE author LIKE ?", (f"%{author}%",)).fetchall()]

    def search(self, query: str):
        q = f"%{query}%"
        return [self._r(r) for r in self._conn.execute(
            "SELECT * FROM books WHERE title LIKE ? OR author LIKE ?", (q,q)).fetchall()]

    def stats(self) -> dict:
        r = self._conn.execute(
            "SELECT COUNT(*) n, ROUND(AVG(price),2) avg, MAX(price) mx, MIN(price) mn FROM books"
        ).fetchone()
        return {"total": r["n"], "avg_price": r["avg"],
                "max_price": r["mx"], "min_price": r["mn"]}

    def update_price(self, book_id: int, price: float) -> bool:
        n = self._conn.execute("UPDATE books SET price=? WHERE id=?", (price, book_id)).rowcount
        self._conn.commit()
        return n > 0

    def delete(self, book_id: int) -> bool:
        n = self._conn.execute("DELETE FROM books WHERE id=?", (book_id,)).rowcount
        self._conn.commit()
        return n > 0

    def _r(self, row) -> Book:
        return Book(id=row["id"], title=row["title"], author=row["author"],
                    price=row["price"], genre=row["genre"])

    def close(self): self._conn.close()
    def __enter__(self): return self
    def __exit__(self, *_): self.close()

if __name__ == "__main__":
    with BookRepo(DB_FILE) as repo:
        repo._conn.execute("DELETE FROM books"); repo._conn.commit()
        repo.add(Book("Кобзар", "Шевченко Т.", 45.0, "Поезія"))
        repo.add(Book("Тигролови", "Багряний І.", 89.0, "Пригоди"))
        repo.bulk_add([
            Book("Harry Potter", "Rowling J.K.", 120.0, "Фентезі"),
            Book("The Little Prince", "Saint-Exupéry", 95.0, "Казка"),
        ])
        print("\\n📚 Всі книги:")
        for b in repo.get_all():
            print(f"  #{b.id} {b.title:<25} | {b.author:<20} | {b.price} грн | {b.genre}")
        found = repo.find_by_author("Шевченко")
        print(f"\\n🔍 Шевченко: {[b.title for b in found]}")
        print(f"\\n📊 Статистика: {repo.stats()}")
    print("\\n✅ Готово! books.db збережено.")`
