        starterCode: `# Урок 86 — Файли та папки
from pathlib import Path
import shutil, os

DEMO_DIR = Path("demo_files")

def setup_demo_files():
    DEMO_DIR.mkdir(exist_ok=True)
    samples = {
        "report.txt": "Звіт", "notes.txt": "Нотатки",
        "photo1.jpg": "img-data", "photo2.jpg": "img-data",
        "song.mp3": "audio-data", "data.csv": "name,value\\nA,1",
    }
    for name, content in samples.items():
        p = DEMO_DIR / name
        if not p.exists():
            p.write_text(content, encoding="utf-8")
    print(f"✅ Створено {len(samples)} файлів")

def list_files(folder):
    print(f"\\n📂 Вміст {folder}:")
    for name in os.listdir(folder):
        full = os.path.join(folder, name)
        kind = "📁" if os.path.isdir(full) else "📄"
        print(f"  {kind} {name}")

def organize_by_extension(folder):
    folder = Path(folder)
    moved = 0
    for item in list(folder.iterdir()):
        if item.is_file():
            ext = item.suffix.lstrip(".") or "other"
            target = folder / f"{ext}_files"
            target.mkdir(exist_ok=True)
            shutil.move(str(item), str(target / item.name))
            moved += 1
    print(f"\\n🗂  Розкладено {moved} файлів")

setup_demo_files()
list_files(DEMO_DIR)
organize_by_extension(DEMO_DIR)
list_files(DEMO_DIR)
print("\\n✅ Готово!")`
