        starterCode: `# Урок 89 — Веб-скрапінг
import requests
from bs4 import BeautifulSoup

URL = "https://example.com"

def fetch_page(url):
    print(f"🌐 Завантажуємо {url} ...")
    response = requests.get(url, timeout=10)
    print(f"   Код відповіді: {response.status_code}")
    if response.status_code != 200:
        print("   ⚠️  Помилка завантаження")
        return None
    return response.text

def parse_page(html):
    soup = BeautifulSoup(html, "html.parser")
    title = soup.find("title")
    print(f"\\n📄 Заголовок: {title.text if title else '(немає)'}")

    headings = soup.find_all(["h1","h2","h3"])
    print(f"\\n📋 Заголовків: {len(headings)}")
    for h in headings:
        print(f"  • {h.text.strip()}")

    links = soup.find_all("a", href=True)
    print(f"\\n🔗 Посилань: {len(links)}")
    for a in links[:10]:
        print(f"  → {a['href']}")

html = fetch_page(URL)
if html:
    parse_page(html)
print("\\n✅ Готово!")`
