        starterCode: `# Урок 90 — Бот-помічник для папок
import os, shutil
from pathlib import Path
from datetime import datetime

WATCH_DIR = Path("watch_folder")
LOG_FILE = "assistant.log"
EXT_MAP = {".txt":"documents",".csv":"documents",".jpg":"images",
           ".png":"images",".mp3":"audio",".mp4":"video"}

def log(action):
    now = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    with open(LOG_FILE, "a", encoding="utf-8") as f:
        f.write(f"[{now}] {action}\\n")
    print(f"📝 {action}")

def setup_demo():
    WATCH_DIR.mkdir(exist_ok=True)
    samples = {"essay.txt":"Текст", "photo.jpg":"img", "music.mp3":"audio", "table.csv":"a,b\\n1,2"}
    for name, content in samples.items():
        p = WATCH_DIR / name
        if not p.exists(): p.write_text(content, encoding="utf-8")

def organize():
    moved = 0
    for item in list(WATCH_DIR.iterdir()):
        if item.is_file():
            category = EXT_MAP.get(item.suffix.lower(), "other")
            target = WATCH_DIR / category
            target.mkdir(exist_ok=True)
            shutil.move(str(item), str(target / item.name))
            moved += 1
    log(f"organize: переміщено {moved} файлів")

def stats():
    counts = {}
    for root, _, files in os.walk(WATCH_DIR):
        for name in files:
            ext = Path(name).suffix or "(без)"
            counts[ext] = counts.get(ext, 0) + 1
    print("\\n📊 Статистика:")
    for ext, n in sorted(counts.items()):
        print(f"  {ext}: {n}")

setup_demo()
organize()
stats()
print("\\n✅ Готово!")`
