        starterCode: `# Урок 102 — Ролі та модерація
import discord, datetime
from discord.ext import commands

TOKEN = "ВСТАВ_СВІЙ_ТОКЕН_ТУТ"
BAD_WORDS = ["погане_слово1", "погане_слово2"]

intents = discord.Intents.default()
intents.message_content = True
intents.members = True
bot = commands.Bot(command_prefix="!", intents=intents)
warnings = {}

@bot.event
async def on_ready():
    print(f"✅ Увійшов як {bot.user}")

@bot.event
async def on_message(message):
    if message.author == bot.user: return
    if any(w in message.content.lower() for w in BAD_WORDS):
        await message.delete()
        await message.channel.send(f"⚠️ {message.author.mention}, таку лексику не використовуємо!")
        return
    await bot.process_commands(message)

@bot.command(name="addrole")
@commands.has_permissions(manage_roles=True)
async def add_role(ctx, member: discord.Member, *, role_name):
    role = discord.utils.get(ctx.guild.roles, name=role_name)
    if not role:
        await ctx.send(f"Роль '{role_name}' не знайдено"); return
    await member.add_roles(role)
    await ctx.send(f"✅ {member.mention} отримав роль {role_name}")

@bot.command(name="whois")
async def whois(ctx, member: discord.Member = None):
    member = member or ctx.author
    roles = [r.name for r in member.roles if r.name != "@everyone"]
    await ctx.send(f"👤 {member.display_name}: {', '.join(roles) or 'без ролей'}")

@bot.command(name="warn")
@commands.has_permissions(kick_members=True)
async def warn(ctx, member: discord.Member, *, reason="не вказано"):
    warnings[member.id] = warnings.get(member.id, 0) + 1
    count = warnings[member.id]
    await ctx.send(f"⚠️ {member.mention} попередження ({count}/3). Причина: {reason}")
    if count >= 3:
        await member.timeout(datetime.timedelta(minutes=10))
        await ctx.send(f"🔇 {member.mention} заглушено на 10 хв")
        warnings[member.id] = 0

if "ВСТАВ" in TOKEN:
    print("⚠️  Спочатку встав токен бота!")
else:
    print("🤖 Бот-модератор запущено!")
    bot.run(TOKEN)`
