        starterCode: `# Урок 104 — NumPy масиви
import numpy as np

def basics_demo():
    grades = np.array([95, 78, 88, 92, 65, 73, 99, 55])
    print("📊 Оцінки:", grades)
    print(f"Сума: {grades.sum()}, Середнє: {grades.mean():.1f}")
    print(f"Мінімум: {grades.min()}, Максимум: {grades.max()}")

def filtering_demo():
    grades = np.array([95, 78, 88, 92, 65, 73, 99, 55])
    excellent = grades[grades >= 90]
    print("\\n🌟 Оцінки >= 90:", excellent)
    boosted = grades + 5
    print("Оцінки +5 балів:", np.clip(boosted, 0, 100))

def matrix_demo():
    matrix = np.array([
        [95, 88, 92], [78, 65, 73], [99, 55, 80],
        [88, 91, 85], [60, 70, 75],
    ])
    print("\\n🧮 Матриця оцінок (5 учнів × 3 предмети):")
    print(matrix)
    print("Середнє по учню:", matrix.mean(axis=1).round(1))
    print("Середнє по предмету:", matrix.mean(axis=0).round(1))

basics_demo()
filtering_demo()
matrix_demo()
print("\\n✅ Готово!")`
