        starterCode: `# Урок 109 — Аналіз даних з візуалізацією
import pandas as pd
import numpy as np
import matplotlib.pyplot as plt

np.random.seed(7)
NAMES = ["Олена","Богдан","Аня","Максим","Катя","Денис","Іванна","Петро"]

def generate_data():
    data = []
    for name in NAMES:
        hours = np.random.randint(1, 10)
        grade = min(100, 40 + hours * 6 + np.random.randint(-10, 10))
        data.append({"name": name, "math": np.random.randint(50,100),
                      "ukrainian": np.random.randint(50,100), "hours_studied": hours,
                      "avg_grade": grade})
    return pd.DataFrame(data)

df = generate_data()
print("📋 Дані учнів:")
print(df)

print("\\n🏆 Топ-3 учні:")
print(df.nlargest(3, "avg_grade")[["name","avg_grade"]])

print("\\n📉 Потребують допомоги:")
print(df.nsmallest(3, "avg_grade")[["name","avg_grade"]])

correlation = df["hours_studied"].corr(df["avg_grade"])
print(f"\\n🔗 Кореляція годин навчання та оцінки: {correlation:.2f}")

fig, axes = plt.subplots(1, 2, figsize=(12,5))
axes[0].bar(df["name"], df["avg_grade"], color="#2a9d8f")
axes[0].set_title("Середня оцінка")
axes[0].tick_params(axis="x", rotation=45)

axes[1].scatter(df["hours_studied"], df["avg_grade"], color="#e63946")
coeffs = np.polyfit(df["hours_studied"], df["avg_grade"], 1)
trend = np.poly1d(coeffs)
x_range = np.linspace(df["hours_studied"].min(), df["hours_studied"].max(), 50)
axes[1].plot(x_range, trend(x_range), color="black", linestyle="--")
axes[1].set_title("Години навчання vs Оцінка")

plt.tight_layout()
plt.savefig("class_analysis.png")
print("\\n📈 Графіки збережено у class_analysis.png")
print("\\n✅ Готово!")`
