        starterCode: `# Урок 110 — Що таке Machine Learning?
import random

TRAINING_DATA = [
    (5, "мале"), (95, "велике"), (10, "мале"), (88, "велике"),
    (3, "мале"), (76, "велике"), (20, "мале"), (99, "велике"),
    (1, "мале"), (55, "велике"),
]

def find_best_threshold(data):
    best_threshold = 0
    best_accuracy = 0
    for threshold in range(0, 100, 5):
        correct = 0
        for value, label in data:
            prediction = "велике" if value >= threshold else "мале"
            if prediction == label:
                correct += 1
        accuracy = correct / len(data)
        if accuracy > best_accuracy:
            best_accuracy = accuracy
            best_threshold = threshold
    return best_threshold, best_accuracy

def predict(value, threshold):
    return "велике" if value >= threshold else "мале"

print("🤖 'Навчаємо' просту модель на даних...")
threshold, accuracy = find_best_threshold(TRAINING_DATA)
print(f"✅ Поріг: {threshold} (точність: {accuracy*100:.0f}%)")

print("\\n🔮 Перевіряємо на нових числах:")
test_numbers = [random.randint(0, 100) for _ in range(5)]
for num in test_numbers:
    result = predict(num, threshold)
    print(f"  {num} → {result}")
print("\\n✅ Готово!")`
