        starterCode: `# Урок 117 — Декоратори та контекстні менеджери
import time, functools
from contextlib import contextmanager

def timer(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        elapsed = time.time() - start
        print(f"⏱  {func.__name__} виконалась за {elapsed*1000:.2f} мс")
        return result
    return wrapper

def count_calls(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        wrapper.calls += 1
        print(f"📞 Виклик №{wrapper.calls}")
        return func(*args, **kwargs)
    wrapper.calls = 0
    return wrapper

def repeat(times):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            return [func(*args, **kwargs) for _ in range(times)]
        return wrapper
    return decorator

class Timer:
    def __enter__(self):
        self.start = time.time()
        return self
    def __exit__(self, *args):
        print(f"⏱  Блок виконався за {(time.time()-self.start)*1000:.2f} мс")

@timer
def slow_calculation():
    return sum(i**2 for i in range(100000))

@count_calls
def greet(name):
    return f"Привіт, {name}!"

slow_calculation()
greet("Олена")
greet("Богдан")

with Timer():
    sum(range(1_000_000))

print("\\n✅ Готово!")`
