        starterCode: `# Урок 118 — Генератори та ітератори
import itertools

def countdown(n):
    while n > 0:
        yield n
        n -= 1

def even_numbers(limit):
    for i in range(limit):
        if i % 2 == 0:
            yield i

def infinite_counter():
    n = 0
    while True:
        yield n
        n += 1

class Fibonacci:
    def __init__(self, count):
        self.count = count
        self.a, self.b = 0, 1
        self.index = 0
    def __iter__(self):
        return self
    def __next__(self):
        if self.index >= self.count:
            raise StopIteration
        result = self.a
        self.a, self.b = self.b, self.a + self.b
        self.index += 1
        return result

def chain_lists(*lists):
    for lst in lists:
        yield from lst

print("⬇️  countdown(5):", list(countdown(5)))
print("✌️  even_numbers(10):", list(even_numbers(10)))
print("♾️  infinite (перші 5):", list(itertools.islice(infinite_counter(), 5)))
print("🌀 Фібоначчі (10):", list(Fibonacci(10)))
print("🔗 chain_lists:", list(chain_lists([1,2],[3,4],[5,6])))
print("\\n✅ Готово!")`
